import{_ as p,o as r,c as t,j as a,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"北境极光的魔女-涅血","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/1.血统与训练/3.心智类/北境极光的魔女-涅血.md","filePath":"4.资源分区/1.血统与训练/3.心智类/北境极光的魔女-涅血.md"}'),d={name:"4.资源分区/1.血统与训练/3.心智类/北境极光的魔女-涅血.md"};function o(_,e,l,b,i,c){return r(),t("div",null,[...e[0]||(e[0]=[a("h1",{id:"北境极光的魔女-涅血",tabindex:"-1"},[n("北境极光的魔女-涅血 "),a("a",{class:"header-anchor",href:"#北境极光的魔女-涅血","aria-label":'Permalink to "北境极光的魔女-涅血"'},"​")],-1),a("table",{class:"bannerparthead"},[a("tbody",null,[a("tr",{id:"hdr"},[a("td",{class:"runninghead",nowrap:""},"TMD：绯红庆典040")])])],-1),s('<h1 id="北境极光的魔女-涅血-1" tabindex="-1">北境极光的魔女-涅血 <a class="header-anchor" href="#北境极光的魔女-涅血-1" aria-label="Permalink to &quot;北境极光的魔女-涅血&quot;">​</a></h1><p>北境极光的魔女-涅血<br> 魔幻本质<br> 血统<br> 在人类的世界中，存在着能够操控魔力的存在：魔女。</p><p>而当魔女存在被暴露后，人与魔女的战争便开始了。</p><p>漫长的战争永无止境，而最为强大的白夜一族的魔女也打破了不参加战争的约定。</p><p>于是，作为涅血家族最后一人的魔女，选择帮助人类，杀死了白夜魔女。</p><p>D级：涅血流淌<br> D+600</p><p>涅血一族血脉的特殊之处，是相比于其他魔女的魔力聚集一处，她们的血液本身就流淌着高浓度的玛娜（mana）。</p><p>获得【涅血魔力】【血之炼成】<br> 【涅血魔力】：你获得【灵感视觉】，开启一个特殊能量池，这个能量池被称呼为“涅血魔力”，是一种特殊的魔力变体，上限为你的耐力+决心。<br> 这个能量池在你兑换后初始为空，并且不能自然恢复，只能通过以下的手段恢复：<br> 1.对敌人造成一次伤害，你获得3点涅血魔力<br> 2.杀死一名敌方角色，你获得5点涅血魔力。如果你所杀死的角色的最高强化等级不低于你的最高强化等级，你还能再因此获得3点涅血魔力。<br> 3.受到敌人造成的一次伤害，你获得3点涅血魔力。<br> 你每具有1点传奇耐力和传奇决心都会令恢复的涅血魔力提升1点。<br> 涅血魔力在一天中的回复量不能超过其上限的三倍，且在一场战斗中的消耗量不能超过其上限。</p><p>【血之炼成】：涅血魔力的基础用法，以魔力为引子将身体内的玛娜提取出来用于战斗，以一个迅捷动作消耗2点涅血魔力对自身造成2点不可豁免的严重伤害，本回合你的下一次白刃攻击将带上你鲜红的血液，额外获得5点dp上的能量加值和1点附加成功。</p><p>C级：涅血之约<br> C+1200</p><p>当然，作为主要依靠自身魔力进行战斗的涅血一族，能够在对具有吸收外界魔力作为己用的白夜一族时，能够不落下风。于是，涅血一族成为了“不让白夜魔女参与人类之间战争”这个约定的执行者</p><p>【涅血架势】：将血液提前汇聚到较为方便的使用之处，更快发动血之炼成的技法，进入战斗时你的血将化成带有魔力了红雾环绕在你的周围，你获得2点ap，仅能用于释放【血之炼成】。</p><p>【血之恩惠I】：当你的涅血魔力不为空时，你进行的所有白刃攻击具有【法破】特性，你在使用【血之炼成】时，仅一次，可以再额外再消耗2点涅血魔力对自身造成2点不可豁免的严重伤害，使本次【血之炼成】提供的能量加值增加5点。</p><p>B级：背叛者之血<br> B+2400</p><p>于是，为了结束战争，涅血家族的最后一位魔女参与了杀死白夜魔女的行动，并吸收了白夜魔女的一部分力量，成为了一位特殊的陨星巫使。</p><p>【血债】：你的右臂现在变化成了特殊的鲜红色魔力结晶，因此你的天生防御提升1点，你现在免疫对你右臂上的肢体妨碍点数减值及其严重后果。</p><p>作为陨星巫使，你继承了白夜的魔法特性：特攻，你的白刃攻击将直接斩开对方的魔力护盾，这是一个【破魔15】效果。</p><p>【涅血刃斩】：本场战斗中，如果你已经释放了至少两次【血之炼成】或者你在战斗轮内上一回合击杀了一名敌方单位，你或他人的鲜血将彻底染红你的武器，挥动其将带起锋利的血刃，你进行白刃攻击时你的触及范围增加10米，造成的伤害现在在原本武器造成的伤害与力场伤害中取优。</p><p>【血之恩惠II】：你在使用【血之炼成】时，如果你在本次【血之炼成】中已经使用了【血之恩惠I】的增幅效果，仅一次，可以再额外再消耗4点涅血魔力对自身造成4点不可豁免的严重伤害，使【血之炼成】提供的效果改为：本回合你的下一次白刃攻击额外获得等同于你决心属性点能量加值和等同于你【传奇决心-1】点附加成功 。</p><p>A级：沃尔德安德（world end）</p><p>为了贯彻自己的决定，涅血家族的最后一位魔女开始在世界各地捕猎陨星巫使，在最后，她面对了那位白夜魔女的女儿...</p><p>暂不开放。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',24)])])}const m=p(d,[["render",o]]);export{f as __pageData,m as default};
